diff --git a/llvm/lib/Transforms/Vectorize/SLPVectorizer.cpp b/llvm/lib/Transforms/Vectorize/SLPVectorizer.cpp
index edb2567fa057..4d9571f0a814 100644
--- a/llvm/lib/Transforms/Vectorize/SLPVectorizer.cpp
+++ b/llvm/lib/Transforms/Vectorize/SLPVectorizer.cpp
@@ -8274,6 +8274,12 @@ protected:
     if (isa<PoisonValue>(V1))
       return Builder.createPoison(
           cast<VectorType>(V1->getType())->getElementType(), Mask.size());
+    // Don't try to optimize shuffles where the mask size does not match the
+    // input vector size. The ShuffleInstructionBuilder has more powerful logic
+    // for these cases (e.g., broadcasting scalars).
+    if (cast<VectorType>(V1->getType())->getElementCount().getKnownMinValue() != Mask.size())
+      return nullptr;
+
     SmallVector<int> NewMask(Mask);
     bool IsIdentity = peekThroughShuffles(V1, NewMask, /*SinglePermute=*/true);
     assert(V1 && "Expected non-null value after looking through shuffles.");
